func TestCompactDiffFormatter_Format(t *testing.T) {
	tests := map[string]struct {
		plan    *plans.Plan
		schemas *schemarepo.Schemas
		want    string
	}{
		"empty plan": {
			plan:    &plans.Plan{Changes: plans.NewChangesSrc()},
			schemas: &schemarepo.Schemas{},
			want:    "",
		},
		"single create": {
			plan: &plans.Plan{
				Changes: &plans.ChangesSrc{
					Resources: []*plans.ResourceInstanceChangeSrc{
						{
							Addr: mustParseResourceInstanceAddr("aws_instance.foo"),
							ChangeSrc: plans.ChangeSrc{
								Action: plans.Create,
								After:  plans.DynamicValue{},
							},
						},
					},
				},
			},
			schemas: &schemarepo.Schemas{},
			want: strings.TrimSpace(`
Create:
  [green]+[reset] aws_instance.foo

Summary:
  Create: 1
`) + "\n",
		},
		"mixed actions": {
			plan: &plans.Plan{
				Changes: &plans.ChangesSrc{
					Resources: []*plans.ResourceInstanceChangeSrc{
						{
							Addr: mustParseResourceInstanceAddr("aws_instance.foo"),
							ChangeSrc: plans.ChangeSrc{
								Action: plans.Create,
								After:  plans.DynamicValue{},
							},
						},
						{
							Addr: mustParseResourceInstanceAddr("aws_instance.bar"),
							ChangeSrc: plans.ChangeSrc{
								Action: plans.Update,
								Before: plans.DynamicValue{},
								After:  plans.DynamicValue{},
							},
						},
						{
							Addr: mustParseResourceInstanceAddr("aws_instance.baz"),
							ChangeSrc: plans.ChangeSrc{
								Action: plans.Delete,
								Before: plans.DynamicValue{},
							},
						},
					},
				},
			},
			schemas: &schemarepo.Schemas{},
			want: strings.TrimSpace(`
Create:
  [green]+[reset] aws_instance.foo

Update:
  [yellow]~[reset] aws_instance.bar

Delete:
  [red]-[reset] aws_instance.baz

Summary:
  Create: 1
  Update: 1
  Delete: 1
`) + "\n",
		},
		"multiple resources same action": {
			plan: &plans.Plan{
				Changes: &plans.ChangesSrc{
					Resources: []*plans.ResourceInstanceChangeSrc{
						{
							Addr: mustParseResourceInstanceAddr("aws_instance.one"),
							ChangeSrc: plans.ChangeSrc{
								Action: plans.Create,
								After:  plans.DynamicValue{},
							},
						},
						{
							Addr: mustParseResourceInstanceAddr("aws_instance.two"),
							ChangeSrc: plans.ChangeSrc{
								Action: plans.Create,
								After:  plans.DynamicValue{},
							},
						},
						{
							Addr: mustParseResourceInstanceAddr("aws_instance.three"),
							ChangeSrc: plans.ChangeSrc{
								Action: plans.Create,
								After:  plans.DynamicValue{},
							},
						},
					},
				},
			},
			schemas: &schemarepo.Schemas{},
			want: strings.TrimSpace(`
Create:
  [green]+[reset] aws_instance.one
  [green]+[reset] aws_instance.three
  [green]+[reset] aws_instance.two

Summary:
  Create: 3
`) + "\n",
		},
	}

	formatter := &CompactDiffFormatter{}

	for name, test := range tests {
		t.Run(name, func(t *testing.T) {
			got := formatter.Format(test.plan, test.schemas)
			if got != test.want {
				t.Errorf("wrong result\ngot:\n%s\n\nwant:\n%s\n", got, test.want)
			}
		})
	}
}

func TestCompactDiffFormatter_ActionName(t *testing.T) {
	tests := map[string]struct {
		action plans.Action
		want   string
	}{
		"create": {
			action: plans.Create,
			want:   "Create",
		},
		"update": {
			action: plans.Update,
			want:   "Update",
		},
		"delete": {
			action: plans.Delete,
			want:   "Delete",
		},
		"delete then create": {
			action: plans.DeleteThenCreate,
			want:   "Replace (delete then create)",
		},
		"create then delete": {
			action: plans.CreateThenDelete,
			want:   "Replace (create then delete)",
		},
		"read": {
			action: plans.Read,
			want:   "Read",
		},
		"forget": {
			action: plans.Forget,
			want:   "Forget",
		},
		"create then forget": {
			action: plans.CreateThenForget,
			want:   "Create then forget",
		},
		"no-op": {
			action: plans.NoOp,
			want:   "No-op",
		},
	}

	for name, test := range tests {
		t.Run(name, func(t *testing.T) {
			got := actionName(test.action)
			if got != test.want {
				t.Errorf("wrong action name: got %q, want %q", got, test.want)
			}
		})
	}
}

// Helper function to parse resource instance addresses for testing
func mustParseResourceInstanceAddr(s string) addrs.AbsResourceInstance {
	addr, diags := addrs.ParseAbsResourceInstanceStr(s)
	if diags.HasErrors() {
		panic(diags.Err())
	}
	return addr
}

// Helper to create test DynamicValues
func testDynamicValue(val cty.Value) plans.DynamicValue {
	dv, _ := plans.NewDynamicValue(val, val.Type())
	return dv
}

